"""Restore module - restores gateway configuration from backup"""

import json
import logging
from datetime import datetime

from . import parser

log = logging.getLogger(__name__)


class RestoreManager:
    """Manages gateway configuration restoration from backups."""

    def __init__(self, gateway_client, backup_manager):
        """Initialize restore manager.

        Args:
            gateway_client: Authenticated ATTGateway instance
            backup_manager: BackupManager instance
        """
        self.gateway = gateway_client
        self.backup_manager = backup_manager
        self.changes = []
        self.errors = []

    def restore(self, backup_identifier=None, pages=None, dry_run=False):
        """Restore configuration from backup.

        Args:
            backup_identifier: Backup to restore from (None = latest)
            pages: List of page paths to restore (None = all)
            dry_run: If True, show what would change without applying

        Returns:
            True if restore successful, False otherwise
        """
        # Load backup
        try:
            backup_data = self.backup_manager.load_backup(backup_identifier)
        except FileNotFoundError as e:
            log.error(str(e))
            return False

        log.info("=" * 60)
        log.info("RESTORE FROM BACKUP")
        log.info("=" * 60)
        log.info(f"Backup date:      {backup_data['backup_date']}")
        log.info(f"Firmware version: {backup_data['firmware_version']}")
        log.info(f"Pages in backup:  {backup_data['page_count']}")

        # Check firmware version compatibility
        current_fw = self.gateway.firmware_version
        backup_fw = backup_data['firmware_version']

        if current_fw != backup_fw:
            log.warning("!" * 60)
            log.warning(f"FIRMWARE VERSION MISMATCH!")
            log.warning(f"Current:  {current_fw}")
            log.warning(f"Backup:   {backup_fw}")
            log.warning(f"Restore may not work correctly!")
            log.warning("!" * 60)

        if dry_run:
            log.info("DRY-RUN MODE: No changes will be applied")

        log.info("=" * 60)

        # Determine which pages to restore
        pages_to_restore = pages or list(backup_data['pages'].keys())

        log.info(f"Restoring {len(pages_to_restore)} page(s)...")
        print()

        success = True

        # Restore each page
        for page_path in pages_to_restore:
            if page_path not in backup_data['pages']:
                log.warning(f"Page {page_path} not in backup, skipping")
                continue

            try:
                page_success = self._restore_page(
                    page_path,
                    backup_data['pages'][page_path],
                    dry_run=dry_run
                )
                if not page_success:
                    success = False

            except Exception as e:
                log.error(f"Error restoring {page_path}: {e}")
                self.errors.append(f"{page_path}: {e}")
                success = False

        # Summary
        print()
        log.info("=" * 60)
        log.info("RESTORE SUMMARY")
        log.info("=" * 60)

        if dry_run:
            log.info(f"Changes detected: {len(self.changes)}")
            if self.changes:
                log.info("The following changes would be made:")
                for change in self.changes:
                    log.info(f"  {change}")
        else:
            log.info(f"Changes applied: {len(self.changes)}")
            if self.changes:
                for change in self.changes:
                    log.info(f"  ✓ {change}")

        if self.errors:
            log.error(f"Errors encountered: {len(self.errors)}")
            for error in self.errors:
                log.error(f"  ✗ {error}")

        log.info("=" * 60)

        return success

    def _restore_page(self, page_path, backup_page_data, dry_run=False):
        """Restore a single page.

        Args:
            page_path: Path to page
            backup_page_data: Backup data for this page
            dry_run: If True, don't actually apply changes

        Returns:
            True if successful, False otherwise
        """
        log.info(f"Restoring {page_path} ({backup_page_data['title']})...")

        # Get current state
        try:
            response = self.gateway.get_page(page_path)
            current_html = response.text
        except Exception as e:
            log.error(f"  Failed to fetch current state: {e}")
            return False

        # Extract current forms
        current_forms = parser.extract_all_forms(current_html)

        # Compare with backup
        backup_forms = backup_page_data['forms']

        if len(backup_forms) != len(current_forms):
            log.warning(f"  Form count mismatch: backup has {len(backup_forms)}, "
                       f"current has {len(current_forms)}")

        # For now, restore the first form (most pages have one main form)
        if not backup_forms:
            log.warning(f"  No forms in backup for {page_path}")
            return True

        if not current_forms:
            log.warning(f"  No forms found on current page {page_path}")
            return False

        backup_form = backup_forms[0]
        current_form = current_forms[0]

        # Compare form fields
        differences = self._compare_forms(current_form, backup_form)

        if not differences:
            log.info(f"  ✓ No changes needed")
            return True

        log.info(f"  Found {len(differences)} field difference(s):")
        for field, (current_val, backup_val) in differences.items():
            log.info(f"    {field}: '{current_val}' -> '{backup_val}'")
            self.changes.append(f"{page_path}: {field} changed")

        if dry_run:
            return True

        # Apply the restore
        try:
            # Extract current nonce
            nonce = parser.extract_nonce(current_html)
            if not nonce:
                log.error(f"  Could not extract nonce from {page_path}")
                return False

            # Build form data with backup values
            form_data = dict(backup_form['fields'])
            form_data['nonce'] = nonce  # Use current nonce

            # Submit the form
            response = self.gateway.post_form(page_path, form_data)

            # Check for success
            if response.status_code in (200, 302) or "Changes saved" in response.text:
                log.info(f"  ✓ Restored successfully")

                # Verify the changes
                verify_response = self.gateway.get_page(page_path)
                verify_forms = parser.extract_all_forms(verify_response.text)

                if verify_forms:
                    verify_form = verify_forms[0]
                    remaining_diffs = self._compare_forms(verify_form, backup_form)

                    if not remaining_diffs:
                        log.info(f"  ✓ Verified: all fields match backup")
                        return True
                    else:
                        log.warning(f"  ⚠ Partial restore: {len(remaining_diffs)} fields still differ")
                        return False
                else:
                    log.warning(f"  Could not verify restore")
                    return True

            else:
                log.error(f"  Restore may have failed (no confirmation)")
                return False

        except Exception as e:
            log.error(f"  Failed to apply restore: {e}")
            return False

    def _compare_forms(self, current_form, backup_form):
        """Compare two forms and return differences.

        Args:
            current_form: Current form data
            backup_form: Backup form data

        Returns:
            Dictionary mapping field names to (current_value, backup_value) tuples
        """
        differences = {}

        current_fields = current_form['fields']
        backup_fields = backup_form['fields']

        # Check all backup fields
        for field, backup_value in backup_fields.items():
            # Skip nonce (always changes)
            if field == 'nonce':
                continue

            # Skip submit buttons
            if field in ('Save', 'Submit', 'Apply', 'Continue'):
                continue

            current_value = current_fields.get(field, '')

            # Compare values
            if str(current_value) != str(backup_value):
                differences[field] = (current_value, backup_value)

        return differences

    def diff_backup(self, backup_identifier=None):
        """Show differences between current config and a backup.

        Args:
            backup_identifier: Backup to compare (None = latest)

        Returns:
            True if successful
        """
        # Load backup
        try:
            backup_data = self.backup_manager.load_backup(backup_identifier)
        except FileNotFoundError as e:
            log.error(str(e))
            return False

        print("\n" + "=" * 60)
        print("CONFIGURATION DIFF")
        print("=" * 60)
        print(f"Backup date:      {backup_data['backup_date']}")
        print(f"Firmware version: {backup_data['firmware_version']}")
        print(f"Current firmware: {self.gateway.firmware_version}")
        print("=" * 60)
        print()

        total_diffs = 0

        # Compare each page
        for page_path, backup_page_data in backup_data['pages'].items():
            try:
                # Get current state
                response = self.gateway.get_page(page_path)
                current_html = response.text
                current_forms = parser.extract_all_forms(current_html)

                if not current_forms:
                    continue

                backup_forms = backup_page_data['forms']
                if not backup_forms:
                    continue

                # Compare first form
                current_form = current_forms[0]
                backup_form = backup_forms[0]

                differences = self._compare_forms(current_form, backup_form)

                if differences:
                    print(f"{page_path} ({backup_page_data['title']}):")
                    for field, (current_val, backup_val) in differences.items():
                        print(f"  {field}:")
                        print(f"    Current: {current_val}")
                        print(f"    Backup:  {backup_val}")
                    print()
                    total_diffs += len(differences)

            except Exception as e:
                log.warning(f"Error comparing {page_path}: {e}")

        print("=" * 60)
        if total_diffs > 0:
            print(f"Total differences: {total_diffs}")
        else:
            print("No differences found - current config matches backup")
        print("=" * 60)
        print()

        return True
